{
  "description": "This intermediate-to-advanced PostgreSQL quiz tests understanding of core SQL concepts, advanced features, and subtle gotchas through a mix of familiar and lesser-known topics. The teaching tone is encouraging and engaging, using emojis and playful language to motivate learners while challenging their technical depth.",
  "topics": ["JOIN operations", "NULL handling", "ANSI SQL standards", "Transactions", "Database internals", "Indexing strategies", "Data sampling techniques"],
  "audience": "PostgreSQL developers, database administrators, and SQL practitioners seeking to deepen their expertise in advanced PostgreSQL concepts and edge cases."
}
